file.log-file:
${log\-file\-name}
<#if facility?has_content && severity?has_content>


        ${facility}
        ${severity}

          <#if advance\-action?has_content>
              ${advance\-action}
          </#if>
          <#if advance\-compare?has_content>
              ${advance\-compare}
          </#if>



</#if>

  <#if max\-file\-size?has_content>
    ${max\-file\-size}
  </#if>
  <#if number\-of\-files?has_content>
    ${number\-of\-files}
  </#if>
  <#if rollover\-count?has_content>
    ${rollover\-count}
  </#if>
  <#if retention\-count?has_content>
    ${retention\-count}
  </#if>

<#if pattern\-match?has_content>
  ${pattern\-match}
</#if>
